import React, { useState } from "react";
import axios from "axios";

const ScreenerPage = () => {
  const [filters, setFilters] = useState({
    peBelow: "",
    pbBelow: "",
    roeAbove: "",
    dividendYieldAbove: "",
    priceAbove: "",
    roi1mAbove: "",
    marketCapAbove: "",
  });

  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFilters({ ...filters, [e.target.name]: e.target.value });
  };

  const handleSearch = async () => {
    setLoading(true);
    try {
      const params = {};
      for (let key in filters) {
        if (filters[key] !== "") params[key] = filters[key];
      }
      const res = await axios.get("/api/screener", { params });
      setResults(res.data.results);
    } catch (err) {
      console.error(err);
      alert("Error fetching screener data.");
    }
    setLoading(false);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Stock Screener</h2>

      <div style={{ display: "flex", flexWrap: "wrap", gap: "10px", marginBottom: "20px" }}>
        <input name="peBelow" placeholder="P/E Below" value={filters.peBelow} onChange={handleChange} />
        <input name="pbBelow" placeholder="P/B Below" value={filters.pbBelow} onChange={handleChange} />
        <input name="roeAbove" placeholder="ROE Above (%)" value={filters.roeAbove} onChange={handleChange} />
        <input name="dividendYieldAbove" placeholder="Div Yield Above (%)" value={filters.dividendYieldAbove} onChange={handleChange} />
        <input name="priceAbove" placeholder="Price Above" value={filters.priceAbove} onChange={handleChange} />
        <input name="roi1mAbove" placeholder="1M ROI Above (%)" value={filters.roi1mAbove} onChange={handleChange} />
        <input name="marketCapAbove" placeholder="Market Cap Above (₹)" value={filters.marketCapAbove} onChange={handleChange} />
      </div>

      <button onClick={handleSearch} disabled={loading}>
        {loading ? "Loading..." : "Run Screener"}
      </button>

      <table border="1" cellPadding="6" cellSpacing="0" style={{ marginTop: "20px", width: "100%", fontSize: "14px" }}>
        <thead style={{ background: "#f0f0f0" }}>
          <tr>
            <th>Symbol</th>
            <th>Name</th>
            <th>Price</th>
            <th>P/E</th>
            <th>P/B</th>
            <th>ROE (%)</th>
            <th>Div Yield (%)</th>
            <th>ROI 1M (%)</th>
            <th>Market Cap</th>
            <th>52W High</th>
            <th>52W Low</th>
          </tr>
        </thead>
        <tbody>
          {results.map((stock) => (
            <tr key={stock.symbol}>
              <td>{stock.symbol}</td>
              <td>{stock.name}</td>
              <td>{stock.price?.toFixed(2)}</td>
              <td>{stock.pe?.toFixed(2)}</td>
              <td>{stock.pb?.toFixed(2)}</td>
              <td>{stock.roe?.toFixed(2)}</td>
              <td>{stock.dividendYield?.toFixed(2)}</td>
              <td>{stock.roi1m?.toFixed(2) || "N/A"}</td>
              <td>{stock.marketCap?.toLocaleString()}</td>
              <td>{stock.fiftyTwoWeekHigh}</td>
              <td>{stock.fiftyTwoWeekLow}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ScreenerPage;
